// src/BillsHistory.jsx
import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

const apiBase = "https://prasa-app-yde3.onrender.com";
const green = "#0f9d58";
const lightGreen = "#eaf8f0";

export default function BillsHistory({ employee }) {
  const navigate = useNavigate();
  const [bills, setBills] = useState([]);
  const [startDate, setStartDate] = useState("");
  const [endDate, setEndDate] = useState("");

  useEffect(() => {
    if (employee?.empld) {
      fetchData();
    }
  }, [employee]);

  const fetchData = async () => {
    try {
      const res = await fetch(
        `${apiBase}/bills?empld=${encodeURIComponent(employee.empld)}`
      );
      const data = await res.json();
      setBills(Array.isArray(data) ? data : []);
    } catch (err) {
      console.error("Bills history fetch error:", err);
      setBills([]);
    }
  };

  // ▶ FILTER BY DATE
  const filteredBills = bills.filter((b) => {
    const dateStr = b.created_at?.split?.("T")?.[0] || b.created_at;
    if (startDate && dateStr < startDate) return false;
    if (endDate && dateStr > endDate) return false;
    return true;
  });

  const handleDownloadPDF = () => {
    window.print();
  };

  if (!employee) {
    return (
      <div style={centerScreen}>
        <div>Employee data not found. Please login again.</div>
      </div>
    );
  }

  return (
    <div
      style={{
        minHeight: "100vh",
        background: lightGreen,
        padding: 20,
        fontFamily: "Segoe UI",
      }}
    >
      <div style={card}>
        {/* Header */}
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <button onClick={() => navigate("/history")} style={backBtn}>
            ⬅ Back
          </button>
          <h2 style={{ color: green, margin: 0 }}>Bills Upload History</h2>
        </div>

        <p style={{ fontSize: 13, color: "#555", marginTop: 6 }}>
          Employee: {employee.name} • {employee.empld}
        </p>

        {/* STEP 1: FILTERS (DATE ONLY) */}
        <div style={filterBar}>
          <div style={filterBlock}>
            <span>From Date</span>
            <input
              type="date"
              value={startDate}
              onChange={(e) => setStartDate(e.target.value)}
              style={filterInput}
            />
          </div>

          <div style={filterBlock}>
            <span>To Date</span>
            <input
              type="date"
              value={endDate}
              onChange={(e) => setEndDate(e.target.value)}
              style={filterInput}
            />
          </div>

          <button
            onClick={() => {
              setStartDate("");
              setEndDate("");
            }}
            style={clearBtn}
          >
            Clear Filters
          </button>
        </div>

        {/* STEP 2: HISTORY TABLE */}
        <table style={tableStyle}>
          <thead>
            <tr>
              <th>Date</th>
              <th>File Name</th>
              <th>Preview</th>
            </tr>
          </thead>
          <tbody>
            {filteredBills.map((b) => (
              <tr key={b.id}>
                <td>{b.created_at?.split?.("T")?.[0] || b.created_at}</td>
                <td>{b.fileName || b.filename}</td>
                <td>
                  {b.filePath && (
                    <a
                      href={`${apiBase}${b.filePath}`}
                      target="_blank"
                      rel="noreferrer"
                    >
                      Open
                    </a>
                  )}
                </td>
              </tr>
            ))}
            {filteredBills.length === 0 && (
              <tr>
                <td colSpan="3" style={{ textAlign: "center", padding: 10 }}>
                  No bills match your filters.
                </td>
              </tr>
            )}
          </tbody>
        </table>

        {/* STEP 3: DOWNLOAD BUTTON AT BOTTOM */}
        <div style={{ display: "flex", justifyContent: "flex-end", marginTop: 14 }}>
          <button onClick={handleDownloadPDF} style={downloadBtn}>
            Download PDF
          </button>
        </div>
      </div>
    </div>
  );
}

// ---------- Styles ----------
const centerScreen = {
  minHeight: "100vh",
  background: lightGreen,
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  fontFamily: "Segoe UI",
};

const card = {
  maxWidth: 950,
  margin: "0 auto",
  background: "#ffffff",
  borderRadius: 16,
  padding: 20,
  boxShadow: "0 6px 20px rgba(0,0,0,0.12)",
};

const backBtn = {
  background: "transparent",
  border: "none",
  color: green,
  fontSize: 16,
  cursor: "pointer",
};

const filterBar = {
  display: "flex",
  flexWrap: "wrap",
  gap: 10,
  alignItems: "center",
  margin: "14px 0",
  background: "#f9fff9",
  borderRadius: 10,
  padding: 10,
  border: "1px solid #eaf8f0",
};

const filterBlock = {
  display: "flex",
  flexDirection: "column",
  fontSize: 12,
};

const filterInput = {
  padding: "4px 6px",
  borderRadius: 6,
  border: "1px solid #ccc",
  fontSize: 12,
};

const clearBtn = {
  padding: "6px 10px",
  borderRadius: 8,
  border: "1px solid #ccc",
  background: "#fff",
  fontSize: 12,
  cursor: "pointer",
};

const downloadBtn = {
  padding: "8px 14px",
  borderRadius: 20,
  border: "none",
  background: green,
  color: "#fff",
  fontSize: 13,
  cursor: "pointer",
};

const tableStyle = {
  width: "100%",
  borderCollapse: "collapse",
  fontSize: 13,
};
